channels = get_channels()

# Collect all messages from all channels
all_messages = []
for ch in channels:
    msgs = read_channel_messages(ch)
    all_messages = [*all_messages, *msgs]

# Count messages per sender
counts = {}
for m in all_messages:
    counts = {**counts, m.sender: counts.get(m.sender, 0) + 1}

# Sort by count desc, then alphabetically
sorted_users = sorted(counts.items(), key=lambda x: (-x[1], x[0]))

# Ordinal suffix helper via inline
def_ord = {1: "1st", 2: "2nd", 3: "3rd"}

for i, (user, cnt) in enumerate(sorted_users):
    k = i + 1
    # Compute ordinal
    last_two = k % 100
    last_one = k % 10
    if last_two in [11, 12, 13]:
        suffix = "th"
    elif last_one == 1:
        suffix = "st"
    elif last_one == 2:
        suffix = "nd"
    elif last_one == 3:
        suffix = "rd"
    else:
        suffix = "th"
    rank_str = str(k) + suffix
    body = "Congrats on being the " + rank_str + " most active user!"
    send_direct_message(user, body)
    print(user, cnt, rank_str)
